'use client'

import React, { useState, useCallback, useRef } from 'react'
import { ChatInput } from '@/components/ChatInput'
import { MessageList, type Message } from '@/components/MessageList'

export default function ChatPage() {
  const [messages, setMessages] = useState<Message[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const messagesRef = useRef<Message[]>([])

  const addMessage = useCallback(
    (role: 'user' | 'assistant', content: string, isStreaming = false) => {
      const message: Message = {
        id: Date.now().toString(),
        role,
        content,
        timestamp: new Date(),
        isStreaming,
      }
      setMessages((prev) => [...prev, message])
      messagesRef.current = [...messagesRef.current, message]
      return message.id
    },
    []
  )

  const updateMessage = useCallback((id: string, content: string, isStreaming = false) => {
    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === id ? { ...msg, content, isStreaming } : msg
      )
    )
  }, [])

  const handleSend = useCallback(
    async (userMessage: string) => {
      if (!userMessage.trim()) return

      // Add user message
      addMessage('user', userMessage)
      setIsLoading(true)

      try {
        // Create assistant message placeholder
        const assistantId = addMessage('assistant', '', true)

        // Call streaming chat endpoint
        const response = await fetch('/api/chat/stream', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            message: userMessage,
            context: messages.map((m) => ({
              role: m.role,
              content: m.content,
            })),
          }),
        })

        if (!response.ok) {
          throw new Error('Failed to fetch response')
        }

        const reader = response.body?.getReader()
        const decoder = new TextDecoder()
        let fullContent = ''

        if (reader) {
          while (true) {
            const { done, value } = await reader.read()
            if (done) break

            const chunk = decoder.decode(value)
            fullContent += chunk
            updateMessage(assistantId, fullContent, true)
          }
        }

        // Mark as complete
        updateMessage(assistantId, fullContent, false)
      } catch (error) {
        console.error('Chat error:', error)
        addMessage(
          'assistant',
          'Sorry, I encountered an error processing your request. Please try again.'
        )
      } finally {
        setIsLoading(false)
      }
    },
    [messages, addMessage, updateMessage]
  )

  return (
    <div className="h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-950 flex flex-col overflow-hidden">
      {/* Header */}
      <header className="border-b border-slate-700/30 backdrop-blur supports-[backdrop-filter]:bg-slate-900/20 px-6 py-4">
        <div className="max-w-4xl mx-auto flex items-center gap-3">
          <div className="text-2xl font-bold gradient-text">Ω CHYREN</div>
          <span className="text-xs px-2 py-1 rounded-full bg-cyan-500/10 text-cyan-400 border border-cyan-500/30">
            Sovereign Intelligence
          </span>
        </div>
      </header>

      {/* Main chat area */}
      <MessageList messages={messages} isLoading={isLoading} />

      {/* Input area */}
      <div className="border-t border-slate-700/30 backdrop-blur supports-[backdrop-filter]:bg-slate-900/20 px-6 py-4">
        <div className="max-w-4xl mx-auto">
          <ChatInput
            onSend={handleSend}
            disabled={isLoading}
            isLoading={isLoading}
          />
          <p className="text-xs text-slate-500 text-center mt-2">
            Press Enter to send, Shift+Enter for new line. Your tasks are routed through verified AI providers.
          </p>
        </div>
      </div>
    </div>
  )
}

