import { NextRequest, NextResponse } from 'next/server';
import { validateChatRequest, checkRateLimit, checkPromptInjection } from '../../../lib/hardening';
import { DialogLoopDetector } from '../../../lib/validators/dialog';

export async function POST(req: NextRequest) {
    const encoder = new TextEncoder();
    const stream = new ReadableStream({
        async start(controller) {
            const ip = req.ip || 'anonymous';

            // 1. Structural Validation
            if (!(await validateChatRequest(req))) {
                controller.enqueue(encoder.encode(JSON.stringify({ error: 'Unauthorized' })));
                controller.close();
                return;
            }

            // 2. Rate Limiting
            if (!checkRateLimit(ip)) {
                controller.enqueue(encoder.encode(JSON.stringify({ error: 'Rate limit exceeded' })));
                controller.close();
                return;
            }

            const body = await req.json();
            const { prompt, history } = body;

            // 3. Prompt Injection Defense
            if (checkPromptInjection(prompt)) {
                controller.enqueue(encoder.encode(JSON.stringify({ error: 'Security constraint violation' })));
                controller.close();
                return;
            }

            // 4. Dialog Loop Detection
            if (DialogLoopDetector(history)) {
                controller.enqueue(encoder.encode(JSON.stringify({ error: 'Dialog loop detected' })));
                controller.close();
                return;
            }

            // 5. Stream from Sovereign Hub (Mock Stream)
            const mockResponse = `Sovereign Hub streaming: Thinking... Analyzing History... Success.`;
            for (const char of mockResponse) {
                controller.enqueue(encoder.encode(JSON.stringify({ chunk: char })));
                await new Promise((resolve) => setTimeout(resolve, 50));
            }
            controller.close();
        },
    });

    return new NextResponse(stream, {
        headers: {
            'Content-Type': 'text/event-stream',
            'Cache-Control': 'no-cache',
            'Connection': 'keep-alive',
        },
    });
}

